classify(N) when N < 0 -> negative;
classify(0) -> zero;
classify(N) when N > 0, N rem 2 =:= 0 -> positive_even;
classify(N) when is_integer(N) -> positive_odd.
%% is_integer/1 and comparisons are guard-safe BIFs

process_flag(trap_exit, true),
try risky() of
    Result -> {ok, Result}
catch
    throw:Reason -> {thrown, Reason};
    error:badarg -> {error, bad_argument};
    exit:Why     -> {exited, Why}
end.
